import { AmbientLight, Color, Mesh, MeshStandardNodeMaterial, PerspectiveCamera, PointLight, Scene, Timer, TorusKnotGeometry, WebGPURenderer } from 'three/webgpu';
import { uniform, sin, cos, time, uv, vec3, mix, float, positionLocal, normalLocal } from 'three/tsl';

function TSLCanvas({ params }) {
  const mountRef = useRef(null);
  const stateRef = useRef(null);

  useEffect(() => {
    const el = mountRef.current;
    const w = el.clientWidth;
    const h = el.clientHeight;

    const scene = new Scene();
    const camera = new PerspectiveCamera(50, w / h, 0.1, 100);
    camera.position.z = 4;

    const renderer = new WebGPURenderer({ antialias: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(window.devicePixelRatio);
    el.appendChild(renderer.domElement);

    scene.add(new AmbientLight(0xffffff, 0.5));
    const point = new PointLight(0xffffff, 1.5, 100);
    point.position.set(5, 5, 5);
    scene.add(point);

    const colorAU = uniform(new Color(0x22d3ee));
    const colorBU = uniform(new Color(0xa78bfa));

    const t = time;
    const uvNode = uv();
    const wave = sin(uvNode.x.mul(6.28).add(t)).mul(0.5).add(0.5);
    const pulse = cos(t.mul(0.7)).mul(0.5).add(0.5);
    const blend = mix(vec3(colorAU), vec3(colorBU), wave.mul(pulse));

    const mat = new MeshStandardNodeMaterial();
    mat.colorNode = blend;
    mat.roughnessNode = float(0.3);
    mat.metalnessNode = float(0.7);

    const displaceAmount = sin(positionLocal.y.mul(4.0).add(t)).mul(0.08);
    mat.positionNode = positionLocal.add(normalLocal.mul(displaceAmount));

    const geo = new TorusKnotGeometry(1, 0.35, 128, 32);
    const mesh = new Mesh(geo, mat);
    scene.add(mesh);

    const targetA = new Color(0x22d3ee);
    const targetB = new Color(0xa78bfa);
    const st = { mesh, scene, camera, renderer, colorAU, colorBU, targetA, targetB };
    stateRef.current = st;

    let raf;
    const timer = new Timer();
    function animate() {
      raf = requestAnimationFrame(animate);
      timer.update();
      const dt = timer.getDelta();
      mesh.rotation.x += 0.3 * dt;
      mesh.rotation.y += 0.6 * dt;
      st.colorAU.value.lerp(st.targetA, Math.min(1, 2.5 * dt));
      st.colorBU.value.lerp(st.targetB, Math.min(1, 2.5 * dt));
      renderer.render(scene, camera);
    }

    renderer.init().then(() => animate());

    const onResize = () => {
      const w2 = el.clientWidth;
      const h2 = el.clientHeight;
      camera.aspect = w2 / h2;
      camera.updateProjectionMatrix();
      renderer.setSize(w2, h2);
    };
    window.addEventListener('resize', onResize);

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      geo.dispose();
      mat.dispose();
      el.removeChild(renderer.domElement);
    };
  }, []);

  useEffect(() => {
    const s = stateRef.current;
    if (!s) return;
    s.targetA.set(params.colorA);
    s.targetB.set(params.colorB);
  }, [params.colorA, params.colorB]);

  return <div ref={mountRef} className="flex-1" />;
}

function TSLStatusBar({ params }) {
  return (
    <div className="px-6 py-4 bg-zinc-900/50 border-t border-zinc-800/50 flex items-center gap-6 flex-wrap">
      <Stat label="Color A">
        <span className="w-4 h-4 rounded-full border border-zinc-700" style={{backgroundColor: params.colorA}} />
      </Stat>
      <Stat label="Color B">
        <span className="w-4 h-4 rounded-full border border-zinc-700" style={{backgroundColor: params.colorB}} />
      </Stat>
      <Stat label="Backend">
        <span className="text-xs font-mono px-2 py-0.5 rounded bg-violet-500/20 text-violet-300">WebGPU / TSL</span>
      </Stat>
    </div>
  );
}

